// NavBar.js
import React, { useState } from "react";
import search from "../assets/search.png";
import "./searchbar.css"; // Import CSS file for styling
import Notify from "./ErrorNotification";

function Search() {
  const [searchQuery, setSearchQuery] = useState("");
  const [showNotification, setShowNotification] = useState(false);

  const handleInputChange = (event) => {
    setSearchQuery(event.target.value);
  };

  const handleSearch = () => {
    console.log("Searching for", searchQuery);
    if (searchQuery !== "") {
      window.location.href = `/marketplace?q=${searchQuery}`;
    } else if (showNotification === false){  // check to prevent spamming the notification
      setShowNotification(true);
      setTimeout(() => {
        setShowNotification(false); // Hide notification after 3 seconds
      }, 3300);
    }
  };

  const handleKeyPress = (event) => {
    if (event.key === "Enter" && searchQuery !== "") {
      window.location.href = `/marketplace?q=${searchQuery}`;
    } else if (showNotification === false && event.key === "Enter") {
      setShowNotification(true);
      setTimeout(() => {
        setShowNotification(false); // Hide notification after 3 seconds
      }, 3300);
    }
  };

  return (
    <div className="search-container">
      <input
        type="text"
        placeholder="Search for products..."
        value={searchQuery}
        onChange={handleInputChange}
        onKeyDown={handleKeyPress}
        className="search-input"
      />
      <button type="submit" onClick={handleSearch} className="search-button">
        <img src={search} alt="search-icon" className="search-img" />
      </button>
      {showNotification && <Notify message="Search field is Empty" />}
    </div>
  );
}

export default Search;
